  "inlineSchema": "// Schema do sistema CONTROL - substitui a planilha Google Sheets.\n// Entidades base (cadastro), lançamentos manuais e o Lead como\n// registro central do funil comercial (preenchido progressivamente).\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  SDR\n  CLOSER\n}\n\nenum Origem {\n  PAGO\n  ORGANICO\n}\n\nenum ReuniaoStatus {\n  PENDENTE\n  FEITA\n  NO_SHOW\n}\n\nenum Resultado {\n  EM_ANDAMENTO\n  GANHO\n  PERDIDO\n}\n\n// Cadastro de membros da equipe (SDRs e Closers).\nmodel TeamMember {\n  id        String   @id @default(cuid())\n  nome      String\n  role      Role\n  ativo     Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  leadsComoSdr    Lead[] @relation(\"SdrLeads\")\n  leadsComoCloser Lead[] @relation(\"CloserLeads\")\n}\n\n// Cadastro de criativos (peças de anúncio).\nmodel Criativo {\n  id        String   @id @default(cuid())\n  nome      String\n  ativo     Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  leads         Lead[]\n  investimentos CriativoMensal[]\n}\n\n// Investimento mensal por criativo + marcação de vencedor.\nmodel CriativoMensal {\n  id           String   @id @default(cuid())\n  criativoId   String\n  criativo     Criativo @relation(fields: [criativoId], references: [id], onDelete: Cascade)\n  mes          String // formato \"YYYY-MM\"\n  investimento Float\n  vencedor     Boolean  @default(false)\n\n  @@unique([criativoId, mes])\n}\n\n// Lista fixa de motivos de não-fechar-proposta na reunião.\nmodel MotivoNaoProposta {\n  id    String  @id @default(cuid())\n  nome  String  @unique\n  ativo Boolean @default(true)\n\n  leads Lead[]\n}\n\n// Entidade central: um lead, atualizado progressivamente ao longo do funil.\nmodel Lead {\n  id     String   @id @default(cuid())\n  data   DateTime // data de entrada do lead\n  origem Origem\n\n  criativoId String?\n  criativo   Criativo? @relation(fields: [criativoId], references: [id])\n\n  sdrId String?\n  sdr   TeamMember? @relation(\"SdrLeads\", fields: [sdrId], references: [id])\n\n  qualificado Boolean?\n  agendou     Boolean?\n\n  reuniaoStatus ReuniaoStatus @default(PENDENTE)\n\n  closerId String?\n  closer   TeamMember? @relation(\"CloserLeads\", fields: [closerId], references: [id])\n\n  fezProposta Boolean?\n\n  motivoNaoPropostaId String?\n  motivoNaoProposta   MotivoNaoProposta? @relation(fields: [motivoNaoPropostaId], references: [id])\n\n  resultado Resultado @default(EM_ANDAMENTO)\n  receita   Float?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([data])\n  @@index([sdrId])\n  @@index([closerId])\n}\n\n// Investimento diário em mídia (independe de criativo específico).\nmodel InvestimentoDiario {\n  id    String   @id @default(cuid())\n  data  DateTime @unique\n  valor Float\n}\n\n// Métricas mensais de operação (para NPS, LTV, Payback CAC, Churn, NRR).\nmodel MetricaMensal {\n  id  String @id @default(cuid())\n  mes String @unique // \"YYYY-MM\"\n\n  custoComercial Float // custo total da operação comercial no mês (para CAC)\n\n  logosInicio   Int\n  logosPerdidos Int\n\n  mrrInicio   Float\n  mrrPerdido  Float\n  mrrExpansao Float\n\n  clientesAtivos Int\n\n  promotores Int\n  neutros    Int\n  detratores Int\n\n  faturamento Float\n}\n\n// Metas do mês.\nmodel MetaMensal {\n  id                 String @id @default(cuid())\n  mes                String @unique // \"YYYY-MM\"\n  metaLeads          Int\n  metaFechamentos    Int\n  metaReceita        Float\n  metaCplQualificado Float\n}\n",
